import{_ as s,c as a,o as t,aN as e}from"./chunks/framework.DXgs1r1w.js";const b=JSON.parse('{"title":"RAG 工作机制详解","description":"","frontmatter":{"date":"2026-07-16T17:30:00.000Z","title":"RAG 工作机制详解","permalink":"/pages/ra834c","categories":["AI","RAG"]},"headers":[],"relativePath":"AI/02.RAG/RAG工作机制详解.md","filePath":"AI/02.RAG/RAG工作机制详解.md","lastUpdated":1784195928000}'),r={name:"AI/02.RAG/RAG工作机制详解.md"};function l(i,n,p,o,d,u){return t(),a("div",null,[...n[0]||(n[0]=[e(`<h1 id="rag-工作机制详解" tabindex="-1">RAG 工作机制详解 <a class="header-anchor" href="#rag-工作机制详解" aria-label="Permalink to &quot;RAG 工作机制详解&quot;">​</a></h1><h2 id="一、总体介绍" tabindex="-1">一、总体介绍 <a class="header-anchor" href="#一、总体介绍" aria-label="Permalink to &quot;一、总体介绍&quot;">​</a></h2><p><strong>RAG（Retrieval-Augmented Generation，检索增强生成）</strong> 是一种将**&quot;检索&quot;与&quot;生成&quot;结合<strong>的 AI 架构：在让 LLM 回答之前，先从外部知识库</strong>检索<strong>相关文档片段，把它们作为上下文喂给 LLM，再由其</strong>生成**答案。</p><h3 id="为什么需要-rag" tabindex="-1">为什么需要 RAG？ <a class="header-anchor" href="#为什么需要-rag" aria-label="Permalink to &quot;为什么需要 RAG？&quot;">​</a></h3><p>LLM 本身存在三大短板，RAG 恰好补上：</p><ul><li><strong>知识滞后</strong>：模型训练后世界在变，它不知道最新信息。</li><li><strong>知识私有</strong>：企业内部的文档、数据库它没见过。</li><li><strong>幻觉</strong>：模型可能一本正经地编造答案。</li></ul><p>RAG 让答案**&quot;有据可依&quot;**——引用真实检索到的资料，显著提升准确性与可溯源。</p><h3 id="典型使用场景" tabindex="-1">典型使用场景 <a class="header-anchor" href="#典型使用场景" aria-label="Permalink to &quot;典型使用场景&quot;">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>说明</th></tr></thead><tbody><tr><td>企业知识库问答</td><td>内部制度、FAQ、产品文档的智能客服</td></tr><tr><td>私域文档检索</td><td>合同、研报、论文的问答与摘要</td></tr><tr><td>客服/助手</td><td>基于帮助文档回答用户问题</td></tr><tr><td>代码助手</td><td>检索内部代码库/API 文档辅助编程</td></tr><tr><td>实时信息</td><td>结合联网检索回答最新事件</td></tr></tbody></table><h3 id="大致流程-一句话版" tabindex="-1">大致流程（一句话版） <a class="header-anchor" href="#大致流程-一句话版" aria-label="Permalink to &quot;大致流程（一句话版）&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>离线：文档 → 分片 → 向量化 → 建索引（存入向量库）</span></span>
<span class="line"><span>在线：提问 → 向量化 → 召回 → 重排 → 拼上下文 → LLM 生成答案</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><hr><h2 id="二、逐步拆解-五个核心环节" tabindex="-1">二、逐步拆解：五个核心环节 <a class="header-anchor" href="#二、逐步拆解-五个核心环节" aria-label="Permalink to &quot;二、逐步拆解：五个核心环节&quot;">​</a></h2><p>下面按&quot;数据从原始文档到最终答案&quot;的顺序，拆解 <strong>分片 → 索引 → 召回 → 重排 → 生成</strong>。</p><h3 id="_1-分片-chunking" tabindex="-1">1. 分片（Chunking） <a class="header-anchor" href="#_1-分片-chunking" aria-label="Permalink to &quot;1. 分片（Chunking）&quot;">​</a></h3><ul><li><strong>做什么</strong>：把长文档切成一个个较小的<strong>文本块（Chunk）</strong>，便于精确检索与向量化。</li><li><strong>为什么</strong>：LLM 上下文窗口有限；整篇文档向量化会丢失细节，且检索粒度太粗。</li><li><strong>常见策略</strong>： <ul><li><strong>固定长度切分</strong>：按字符/Token 数（如 512 Token）硬切，简单但可能切断语义。</li><li><strong>语义切分</strong>：按段落、标题、句子边界切分，保留语义完整。</li><li><strong>递归切分</strong>：优先在段落/换行处切，退而求其次再按句子、词切。</li><li><strong>重叠（Overlap）</strong>：相邻块保留一定重叠，避免信息被切断在边界上。</li></ul></li><li><strong>关键权衡</strong>：块太小→检索精准但缺上下文；块太大→有上下文但噪声多、向量变模糊。</li></ul><h3 id="_2-索引-indexing" tabindex="-1">2. 索引（Indexing） <a class="header-anchor" href="#_2-索引-indexing" aria-label="Permalink to &quot;2. 索引（Indexing）&quot;">​</a></h3><ul><li><strong>做什么</strong>：把每个 Chunk <strong>向量化</strong>（Embedding），并建立可快速检索的索引，存入<strong>向量数据库</strong>。</li><li><strong>向量化</strong>：用 Embedding 模型（如 OpenAI text-embedding、BGE、百川等）把文本转成高维向量，语义相近的文本向量也相近。</li><li><strong>存储</strong>：写入向量数据库（如 Milvus、Qdrant、pgvector、Faiss、Chroma）。</li><li><strong>索引结构</strong>：常用 <strong>ANN（近似最近邻）</strong> 索引（如 HNSW、IVF），在速度与精度间权衡，支持海量向量下的毫秒级检索。</li><li><strong>补充索引</strong>：除向量外，常同时存原文、元数据（来源、时间、标题），便于回带与过滤。</li></ul><h3 id="_3-召回-retrieval-recall" tabindex="-1">3. 召回（Retrieval / Recall） <a class="header-anchor" href="#_3-召回-retrieval-recall" aria-label="Permalink to &quot;3. 召回（Retrieval / Recall）&quot;">​</a></h3><ul><li><strong>做什么</strong>：用户提问时，把问题也<strong>向量化</strong>，去向量库里找<strong>最相似的 Top-K 个 Chunk</strong>。</li><li><strong>相似度度量</strong>：余弦相似度（Cosine）、内积（Dot Product）、欧氏距离。</li><li><strong>召回特点</strong>：<strong>宁多勿漏</strong>——尽可能把可能相关的都捞回来（如 Top 20~50），后续交给重排精筛。</li><li><strong>增强手段</strong>： <ul><li><strong>混合检索（Hybrid）</strong>：向量检索（语义）+ 关键词检索（BM25，精确词匹配）融合，兼顾语义与字面。</li><li><strong>元数据过滤</strong>：先按时间/来源/权限筛掉无关文档，再向量检索。</li></ul></li></ul><h3 id="_4-重排-reranking" tabindex="-1">4. 重排（Reranking） <a class="header-anchor" href="#_4-重排-reranking" aria-label="Permalink to &quot;4. 重排（Reranking）&quot;">​</a></h3><ul><li><strong>做什么</strong>：对召回的候选 Chunk 用<strong>更精细的模型</strong>重新打分排序，挑出最相关的一小部分（如 Top 3~5）给 LLM。</li><li><strong>为什么需要</strong>：召回阶段为了快用了轻量 ANN，精度有限；重排用 Cross-Encoder 类模型同时看&quot;问题+文档&quot; pair，排序质量更高。</li><li><strong>常见做法</strong>： <ul><li><strong>Reranker 模型</strong>（如 BGE-Reranker、Cohere Rerank）：对(query, doc)打分，相关性判断更准。</li><li><strong>规则融合</strong>：RRF（Reciprocal Rank Fusion）把多路召回结果按排名融合。</li></ul></li><li><strong>价值</strong>：大幅提升送入 LLM 的上下文质量，直接改善最终答案准确率。</li></ul><h3 id="_5-生成-generation" tabindex="-1">5. 生成（Generation） <a class="header-anchor" href="#_5-生成-generation" aria-label="Permalink to &quot;5. 生成（Generation）&quot;">​</a></h3><ul><li><strong>做什么</strong>：把<strong>重排后的相关 Chunk + 用户问题</strong>拼成 Prompt，交给 LLM 生成最终回答。</li><li><strong>Prompt 构造</strong>：通常形如<div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是一个严谨的助手，仅根据下面的【参考资料】回答，</span></span>
<span class="line"><span>若资料中没有答案就说&quot;不知道&quot;，不要编造。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【参考资料】</span></span>
<span class="line"><span>{检索到的 Chunk 1}</span></span>
<span class="line"><span>{检索到的 Chunk 2}</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【问题】{用户提问}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div></li><li><strong>关键点</strong>： <ul><li><strong>约束生成</strong>：要求模型&quot;基于资料作答、注明出处、不知道就说不知道&quot;，抑制幻觉。</li><li><strong>引用溯源</strong>：让答案附带引用块编号，方便用户核对。</li><li><strong>上下文压缩</strong>：若 Chunk 仍过长，可先做摘要再送入，省 Token。</li></ul></li></ul><hr><h2 id="三、全链路回顾" tabindex="-1">三、全链路回顾 <a class="header-anchor" href="#三、全链路回顾" aria-label="Permalink to &quot;三、全链路回顾&quot;">​</a></h2><p>RAG 链路分为两段：<strong>提问前（离线 / 索引链路）</strong> 与 <strong>提问后（在线 / 查询链路）</strong>。</p><h3 id="提问前链路-离线-一次性建设" tabindex="-1">提问前链路（离线，一次性建设） <a class="header-anchor" href="#提问前链路-离线-一次性建设" aria-label="Permalink to &quot;提问前链路（离线，一次性建设）&quot;">​</a></h3><p>目标：把知识库变成&quot;可被检索的向量索引&quot;。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原始文档（PDF/网页/数据库）</span></span>
<span class="line"><span>   │  ① 加载 / 解析（抽取纯文本）</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>文档清洗（去噪、去重、统一格式）</span></span>
<span class="line"><span>   │  ② 分片（Chunking）</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>文本块 Chunk</span></span>
<span class="line"><span>   │  ③ 向量化（Embedding）</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>向量 + 原文 + 元数据</span></span>
<span class="line"><span>   │  ④ 写索引（存入向量库 ANN 索引）</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>        向量数据库（知识底座，长期可用）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><blockquote><p>此阶段与用户提问无关，可在系统上线前批量完成；文档更新时需<strong>增量重建</strong>对应 Chunk 的索引。</p></blockquote><h3 id="提问后链路-在线-每次提问触发" tabindex="-1">提问后链路（在线，每次提问触发） <a class="header-anchor" href="#提问后链路-在线-每次提问触发" aria-label="Permalink to &quot;提问后链路（在线，每次提问触发）&quot;">​</a></h3><p>目标：根据用户问题实时检索并生成答案。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户提问</span></span>
<span class="line"><span>   │  ⑤ 问题向量化（同一 Embedding 模型）</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>向量库检索</span></span>
<span class="line"><span>   │  ⑥ 召回 Top-K 候选 Chunk（ANN + 可选 BM25 混合）</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>候选 Chunk 集合</span></span>
<span class="line"><span>   │  ⑦ 重排（Reranker 精筛 Top-N）</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>精选相关片段</span></span>
<span class="line"><span>   │  ⑧ 拼接 Prompt（资料 + 问题）</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>LLM 生成</span></span>
<span class="line"><span>   │  ⑨ 输出答案（+ 引用溯源）</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>        返回给用户</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><h3 id="两段链路对照" tabindex="-1">两段链路对照 <a class="header-anchor" href="#两段链路对照" aria-label="Permalink to &quot;两段链路对照&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>触发时机</th><th>核心动作</th><th>关键组件</th></tr></thead><tbody><tr><td>提问前（离线）</td><td>建库/更新时</td><td>加载→分片→向量化→建索引</td><td>解析器、Embedding、向量库</td></tr><tr><td>提问后（在线）</td><td>每次提问</td><td>向量化→召回→重排→生成</td><td>Embedding、向量库、Reranker、LLM</td></tr></tbody></table><hr><h2 id="四、核心概念对照表" tabindex="-1">四、核心概念对照表 <a class="header-anchor" href="#四、核心概念对照表" aria-label="Permalink to &quot;四、核心概念对照表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>环节</th><th>一句话</th><th>关键产出</th></tr></thead><tbody><tr><td>分片</td><td>把文档切成合适大小的块</td><td>Chunk 列表</td></tr><tr><td>索引</td><td>把块向量化并建立可检索结构</td><td>向量库索引</td></tr><tr><td>召回</td><td>按语义捞出可能相关的候选</td><td>Top-K Chunk</td></tr><tr><td>重排</td><td>对候选精筛出最相关的少数</td><td>Top-N Chunk</td></tr><tr><td>生成</td><td>结合资料让 LLM 作答</td><td>带出处的最终答案</td></tr></tbody></table><blockquote><p>记忆口诀：<strong>离线&quot;切→嵌→存&quot;，在线&quot;问→捞→筛→答&quot;；分片定粒度，索引供检索，召回求全，重排求准，生成求稳。</strong></p></blockquote><h3 id="常见优化方向" tabindex="-1">常见优化方向 <a class="header-anchor" href="#常见优化方向" aria-label="Permalink to &quot;常见优化方向&quot;">​</a></h3><ul><li><strong>分片策略</strong>：语义切分 + 合理 Overlap，提升检索粒度。</li><li><strong>混合检索</strong>：向量 + BM25 融合，弥补纯向量对专有名词/编号的弱点。</li><li><strong>重排必做</strong>：加 Reranker 通常能显著提升效果。</li><li><strong>元数据过滤</strong>：先过滤再检索，降本增效。</li><li><strong>Query 改写</strong>：把口语化问题改写成更适合检索的查询（如 Hypothetical Document Embeddings）。</li><li><strong>父子分块</strong>：用小块检索、用大块（父块）喂给 LLM，兼顾精度与上下文。</li></ul>`,42)])])}const g=s(r,[["render",l]]);export{b as __pageData,g as default};
